let raw = $input.item.json.choices?.[0]?.message?.content || "{};";
let payload = {};

// 1. Cirugía: Extraer agresivamente solo el bloque {} ignorando el texto conversacional alrededor
let match = raw.match(/\{[\s\S]*\}/);
if (match) {
  raw = match[0];
}

try {
  payload = JSON.parse(raw);

  // Forzar claves mínimas si el LLM las olvida
  if (!payload.titulo) payload.titulo = "Idea Recuperada";
  if (!payload.descripcion) payload.descripcion = $('Execute Workflow Trigger').item.json.texto_usuario;
  if (!payload.categoria) payload.categoria = "General";
  if (!payload.accion_sugerida) payload.accion_sugerida = "Revisar acción manual";

} catch(e) {
  payload = {
    titulo: "Fallo Extracción JSON",
    descripcion: $('Execute Workflow Trigger').item.json.texto_usuario,
    categoria: "Error",
    accion_sugerida: "Depurar salida del LLM"
  };
}

return { json: { payload: payload } };
